INSERT INTO "Review" ("id", "userId", "name", "educationalInstitution", "rating", "text", "isPublished", "createdAt") VALUES
('cmp67i06205i7lk9c08pvtqhe', 'cmp66xiqu00erlktgels8stxw', 'Борисов Кирилл Васильевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '2', 'Курс в итоге закончил, но тянулось тяжело: местами слишком плотно по тексту, а обратная связь по практике шла не так быстро, как хотелось. На троечку тянет, не больше.', 't', '2026-04-13 09:45:40.269'),
('cmp67i06205i9lk9cf4k51j44', 'cmp66xiqy00eulktgttd3n3ek', 'Былчахов Алексей Амирович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-12 04:26:22.85'),
('cmp67i05605exlk9cvzmb4x8j', 'cmp65v9cf00a9lksa715m6g72', 'Дедюхин Андрей', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Курс закончил, но тяжеловато по нагрузке параллельно с парой. Иногда не хватало пошаговых подсказок в практике. Итог: полезно, но не идеально.', 't', '2026-04-16 15:46:53.473'),
('cmp67i05605ezlk9c5dbdhtcv', 'cmp65v9ch00aclksa18wt0dkd', 'Ёлчян Агаси', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '5', 'На втором курсе ИСИП как раз то, что нужно: и термины, и аккуратные сценарии. Прошла полностью, сертификат уже в папке с документами. Рекомендую группе.', 't', '2026-04-14 19:35:34.436'),
('cmp67i06405ihlk9ckxukkvvd', 'cmp66xir600f3lktg7pw4j2lu', 'Динганорбоев Эрдэм Булатович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '5', 'Отлично структурировано: от простого к сложному, везде понятно, зачем этот шаг. Практика с ручной проверкой мотивировала не халтурить. После выдачи сертификата спокойно рассказываю одногруппникам, с чего начать ИБ.', 't', '2026-04-13 17:27:38.028'),
('cmp67i06505ijlk9cf6a94b4w', 'cmp66xir900f6lktgc60qfvaa', 'Еникеев Валерий Александрович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '2', 'Завершила курс из упрямства — в целом полезно, но ожидала большей гибкости по срокам и более разжёванных объяснений в паре модулей. За идею и сертификат спасибо, за подачу — на четвёрку не потянет.', 't', '2026-04-12 14:29:12.505'),
('cmp67i06505illk9c5mdmbagp', 'cmp66xirb00f9lktgmb07qjci', 'Зенков Данил Константинович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '2', 'Завершила курс из упрямства — в целом полезно, но ожидала большей гибкости по срокам и более разжёванных объяснений в паре модулей. За идею и сертификат спасибо, за подачу — на четвёрку не потянет.', 't', '2026-04-14 10:46:39.816'),
('cmp67i06605inlk9cjjfjtlcg', 'cmp66xire00fclktg46hlve7i', 'Илларионов Александр Илларионович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '4', 'На третьем курсе как раз пригодился такой системный курс. Завершил полностью, сертификат приложу к портфолио. За минус — хотелось бы чуть больше видео, но текст хороший.', 't', '2026-04-12 22:17:37.709'),
('cmp67i06605iplk9c4en22d6k', 'cmp66xiri00fflktgq597qve6', 'Иннокентьев Влад Александрович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '4', 'На третьем курсе как раз пригодился такой системный курс. Завершил полностью, сертификат приложу к портфолио. За минус — хотелось бы чуть больше видео, но текст хороший.', 't', '2026-04-08 07:03:17.563'),
('cmp67i06705irlk9c51l77w43', 'cmp66xirm00filktgn0ce3sj7', 'Исаков Илья Игоревич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-10 05:15:05.107'),
('cmp67i06705itlk9clfjbp0pj', 'cmp66xirp00fllktg4tpmffbh', 'Кондаков Виктор Михайлович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-15 20:51:13.589'),
('cmp67i06805ixlk9cdlwzilzg', 'cmp66xiru00frlktgjn9fct63', 'Левин Артем Данилович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '5', 'Отлично выстроено под заочников: короткие сессии, понятные задания. Прошёл до конца без выгорания. Сертификат — приятное завершение.', 't', '2026-04-12 12:28:51.542'),
('cmp67i06a05izlk9cpwbtj6qp', 'cmp5md5z7001ignc06oxib8w5', 'Мелентьев Максим Станиславович', 'Якутский гуманитарный колледж, группа КИ-24, 3 курс', '5', 'Отлично выстроено под заочников: короткие сессии, понятные задания. Прошёл до конца без выгорания. Сертификат — приятное завершение.', 't', '2026-04-13 06:18:17.047'),
('cmp67i06a05j1lk9cduia3nn7', 'cmp66xirx00fulktgsczlecqj', 'Мандаров Артем Викторович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '3', 'Ровный курс: прошла, сертификат на руках. Ни восторга, ни разочарования — как хороший учебник, только интерактивный.', 't', '2026-04-13 06:10:50.512'),
('cmp67i06b05j3lk9caxfle40f', 'cmp66xirz00fxlktgjzcnq2q0', 'Миронов Арсен Сергеевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '3', 'По специальности ОИБ материал зашёл: база закрыта, сертификат получил. Без пятерки — хотелось бы больше разборов «что делать, если уже попались» в бытовых сценариях.', 't', '2026-04-14 09:50:11.685'),
('cmp67i06c05j7lk9c98kol3ny', 'cmp66xis400g3lktgjh1aucr0', 'Николаев Аслан Анатольевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '3', 'Нормальный курс для общей грамотности по ИБ. Всё закрыл, документ выдали. Без восторга, но жаловаться не на что — ровно то, что обещали.', 't', '2026-04-10 05:07:54.027'),
('cmp67i06d05jblk9cijkhf7cn', 'cmp66xis800g9lktgnt5rln9x', 'Оконешников Родион Николаевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-15 10:51:54.489'),
('cmp67i06d05jdlk9cul42pk1w', 'cmp66xisb00gclktgi3bvk3ow', 'Павлуцкий Айсен Егорович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '5', 'Отлично выстроено под заочников: короткие сессии, понятные задания. Прошёл до конца без выгорания. Сертификат — приятное завершение.', 't', '2026-04-13 06:09:30.119'),
('cmp67i06d05jflk9cm5x9w8u6', 'cmp66xisd00gflktg26l9cwxd', 'Рожин Никита Егорович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '4', 'Хорошо стыкуется с тем, что проходим в группе. Прошла все модули, к итоговому документу вопросов нет. Минус балл за то, что AI-подсказки иногда слишком общие.', 't', '2026-04-15 21:31:39.575'),
('cmp67i06e05jhlk9cgqanbyq2', 'cmp66xise00gilktg6iekjp5v', 'Романов Дмитрий Дмитриевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '3', 'Ровный курс: прошла, сертификат на руках. Ни восторга, ни разочарования — как хороший учебник, только интерактивный.', 't', '2026-04-15 16:50:46.4'),
('cmp67i06f05jllk9cb4k9xqut', 'cmp5md5zo001lgnc0cxnvaytv', 'Находкин Дмитрий Романович', 'Якутский гуманитарный колледж, группа КИ-24, 3 курс', '3', 'Нормальный учебный трек: прошёл все модули, документ получил. Ни эйфории, ни разочарования — ровный рабочий материал для старта в теме безопасности.', 't', '2026-04-14 01:38:26.933'),
('cmp67i06f05jnlk9cbt9zin71', 'cmp66xisj00golktgpb7zfxwg', 'Софронеев Айсен Петрович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '5', 'Дошёл до конца, сертификат уже в портфолио. Модули логично цепляются друг за другом, практика после теории реально помогает запомнить. AI-наставник не «делает за тебя», а подсказывает — для меня это плюс.', 't', '2026-04-13 14:15:45.44'),
('cmp67i06e05jjlk9c8zoav5al', 'cmp66xisg00gllktge6btd56f', 'Сафаргалеев Владимир Владимирович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-13 00:46:05.323'),
('cmp67i06h05jtlk9cwli20oh3', 'cmp66xiso00gxlktgolca0pqf', 'Шестаков Дархан Алексеевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '5', 'Очень понравилось, что нельзя «прокликать» практику бездумно — проверка реально заставляет думать. Курс полностью прошёл, сертификатом доволен.', 't', '2026-04-12 12:57:07.453'),
('cmp67i06g05jplk9c7fzf7yb3', 'cmp66xisk00grlktgs4myxl32', 'Степанов Мичил Васильевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '3', 'Нормально для обязательного блока: база по ИБ закрыта, сертификат выдали. Без «вау», но претензий к честности курса нет.', 't', '2026-04-14 11:01:29.163');